import React, { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import {
  getB2bOrderDetail,
  approveB2bOrder,
  updateB2bOrderStatus,
  setB2bTrackingNumber,
} from "../../features/b2b/b2bSlice";
import {
  ArrowLeft,
  ShoppingBag,
  CreditCard,
  User,
  MapPin,
  FileText,
  Truck,
  ShieldCheck,
} from "lucide-react";
import { Button, Select, Input, Table, message, Card, Steps } from "antd";

const B2bOrderDetail = () => {
  const { id } = useParams();
  const dispatch = useDispatch();

  const [trackingInput, setTrackingInput] = useState("");
  const [proformaInput, setProformaInput] = useState("");
  const [taxInvoiceInput, setTaxInvoiceInput] = useState("");
  const [deliveredQtys, setDeliveredQtys] = useState({});

  const { orderDetail, isLoading } = useSelector((state) => state.b2b);

  useEffect(() => {
    dispatch(getB2bOrderDetail(id));
  }, [dispatch, id]);

  useEffect(() => {
    if (orderDetail) {
      setTrackingInput(orderDetail.shipmentTrackingNumber || "");
      setProformaInput(orderDetail.proformaInvoiceUrl || "");
      setTaxInvoiceInput(orderDetail.taxInvoiceUrl || "");

      // Prepopulate delivered quantities from DB
      const qtys = {};
      orderDetail.items?.forEach((item) => {
        qtys[item.id] = item.deliveredQuantity || 0;
      });
      setDeliveredQtys(qtys);
    }
  }, [orderDetail]);

  const handleApprove = () => {
    dispatch(approveB2bOrder(id)).then((res) => {
      if (res.meta.requestStatus === "fulfilled") {
        message.success("Order approved and released for processing.");
      } else {
        message.error("Failed to approve order.");
      }
    });
  };

  const handleUpdateStatus = (status) => {
    dispatch(
      updateB2bOrderStatus({
        id,
        status,
        deliveredQuantities: deliveredQtys,
        proformaInvoiceUrl: proformaInput,
        taxInvoiceUrl: taxInvoiceInput,
      })
    ).then((res) => {
      if (res.meta.requestStatus === "fulfilled") {
        message.success(`Order status updated to ${status}.`);
      } else {
        message.error("Failed to update order status.");
      }
    });
  };

  const handleUpdateTracking = () => {
    dispatch(setB2bTrackingNumber({ id, trackingNumber: trackingInput })).then(
      (res) => {
        if (res.meta.requestStatus === "fulfilled") {
          message.success("Tracking number updated successfully.");
        } else {
          message.error("Failed to update tracking.");
        }
      }
    );
  };

  const handleQtyChange = (itemId, val, max) => {
    const qty = Math.min(max, Math.max(0, parseInt(val) || 0));
    setDeliveredQtys({ ...deliveredQtys, [itemId]: qty });
  };

  if (isLoading || !orderDetail) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] opacity-50">
        <div className="w-8 h-8 rounded-full border-2 border-blue-600 border-t-transparent animate-spin mb-4" />
        <p className="font-black text-slate-400 uppercase tracking-widest text-xs">
          Loading Order Records...
        </p>
      </div>
    );
  }

  // Steps matching B2b status
  const steps = [
    { title: "Review", key: "PENDING_APPROVAL" },
    { title: "Approved", key: "APPROVED" },
    { title: "Processing", key: "PROCESSING" },
    { title: "Shipped", key: "SHIPPED" },
    { title: "Delivered", key: "DELIVERED" },
  ];

  const currentStep = steps.findIndex(
    (s) => s.key === orderDetail.procurementStatus
  );

  const itemColumns = [
    {
      title: "Wholesale Item",
      dataIndex: "product",
      render: (product) => (
        <div className="flex flex-col">
          <span className="font-bold text-slate-900 text-sm">
            {product?.title || "Unknown Product"}
          </span>
          <span className="text-[11px] text-slate-400 font-bold uppercase tracking-widest mt-1">
            SKU: {product?.sku || "N/A"} | Batch: {product?.batchNumber || "N/A"}
          </span>
        </div>
      ),
    },
    {
      title: "Expiry",
      dataIndex: "expiryDate",
      render: (date) =>
        date ? (
          <span className="text-xs font-bold text-rose-500">
            {new Date(date).toLocaleDateString()}
          </span>
        ) : (
          <span className="text-slate-400 text-xs">-</span>
        ),
    },
    {
      title: "Requested Qty",
      dataIndex: "quantity",
      render: (qty, record) => (
        <span className="font-bold text-slate-800 text-sm">
          {qty} <span className="text-[11px] text-slate-400">{record.size}</span>
        </span>
      ),
    },
    {
      title: "Delivered Qty",
      dataIndex: "id",
      render: (_, record) => {
        const isCompleted = ["DELIVERED", "CANCELLED"].includes(
          orderDetail.procurementStatus
        );
        return isCompleted ? (
          <span className="font-black text-emerald-600 text-sm">
            {record.deliveredQuantity} / {record.quantity}
          </span>
        ) : (
          <Input
            type="number"
            className="w-20 rounded-lg text-center font-bold"
            value={deliveredQtys[record.id] ?? 0}
            onChange={(e) =>
              handleQtyChange(record.id, e.target.value, record.quantity)
            }
          />
        );
      },
    },
    {
      title: "Wholesale Price",
      dataIndex: "unitPrice",
      render: (price, record) => (
        <div className="flex flex-col">
          <span className="font-bold text-slate-800">
            {parseFloat(price || record.price).toLocaleString()} ETB
          </span>
          {record.tierPriceApplied && (
            <span className="text-[10px] font-black text-emerald-600 uppercase">
              Tier Price Applied
            </span>
          )}
        </div>
      ),
    },
    {
      title: "Subtotal",
      render: (_, record) => {
        const qty = record.quantity || 0;
        const price = parseFloat(record.unitPrice || record.price || 0);
        return (
          <span className="font-black text-slate-900">
            {(qty * price).toLocaleString()} ETB
          </span>
        );
      },
    },
  ];

  return (
    <div className="space-y-8 pb-12">
      {/* Back Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <Link
            to="/admin/b2b/orders"
            className="p-3 bg-white border border-slate-200 rounded-2xl hover:bg-slate-50 transition-colors shadow-sm"
          >
            <ArrowLeft size={18} className="text-slate-500" />
          </Link>
          <div>
            <span className="text-[11px] font-black text-blue-600 uppercase tracking-[0.2em]">
              Procurement Fulfillment
            </span>
            <h1 className="text-[28px] font-bold text-slate-900 tracking-tight leading-tight">
              Order Details
            </h1>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <span className="text-xs font-black text-slate-400 bg-slate-50 border border-slate-100 rounded-xl px-4 py-2 uppercase">
            REF: {orderDetail.txRef}
          </span>
        </div>
      </div>

      {/* Stepper progress */}
      {orderDetail.procurementStatus !== "CANCELLED" && (
        <div className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm">
          <Steps current={currentStep >= 0 ? currentStep : 0} labelPlacement="vertical">
            {steps.map((s) => (
              <Steps.Step key={s.key} title={s.title} />
            ))}
          </Steps>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Core items and customer details */}
        <div className="lg:col-span-2 space-y-8">
          {/* Items card */}
          <div className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm">
            <div className="flex items-center gap-3 mb-6">
              <ShoppingBag size={20} className="text-slate-400" />
              <h3 className="text-lg font-black text-slate-900">Requested Items</h3>
            </div>
            <Table
              columns={itemColumns}
              dataSource={orderDetail.items || []}
              pagination={false}
              className="modern-table"
              rowKey="id"
            />
            <div className="flex justify-end mt-8 border-t border-slate-50 pt-6">
              <div className="w-64 space-y-3">
                <div className="flex justify-between text-slate-400 text-sm font-bold">
                  <span>Gross Total:</span>
                  <span className="text-slate-700">
                    {parseFloat(orderDetail.totalPrice).toLocaleString()} ETB
                  </span>
                </div>
                <div className="flex justify-between text-lg font-black text-slate-950 border-t border-slate-50 pt-3">
                  <span>Grand Total:</span>
                  <span>
                    {parseFloat(orderDetail.totalPriceAfterDiscount).toLocaleString()} ETB
                  </span>
                </div>
              </div>
            </div>
          </div>

          {/* Customer / Location Info */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {/* Buyer Profile */}
            <div className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm space-y-4">
              <div className="flex items-center gap-3 border-b border-slate-50 pb-4">
                <User size={18} className="text-slate-400" />
                <h4 className="font-bold text-slate-800 text-sm">Customer Profile</h4>
              </div>
              <div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  Institution
                </p>
                <p className="font-bold text-slate-900 text-base">
                  {orderDetail.user?.institutionName || "Individual Account"}
                </p>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    Procurement Officer
                  </p>
                  <p className="font-bold text-slate-700 text-sm">
                    {orderDetail.firstName} {orderDetail.lastName}
                  </p>
                </div>
                <div>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    Phone Contact
                  </p>
                  <p className="font-bold text-slate-700 text-sm">
                    {orderDetail.phone}
                  </p>
                </div>
              </div>
            </div>

            {/* Destination */}
            <div className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm space-y-4">
              <div className="flex items-center gap-3 border-b border-slate-50 pb-4">
                <MapPin size={18} className="text-slate-400" />
                <h4 className="font-bold text-slate-800 text-sm">Shipping Destination</h4>
              </div>
              <div>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  Address Line
                </p>
                <p className="font-bold text-slate-700 text-sm">
                  {orderDetail.address}
                </p>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    City / Country
                  </p>
                  <p className="font-bold text-slate-700 text-sm">
                    {orderDetail.city}, {orderDetail.country}
                  </p>
                </div>
                <div>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    Postal Code
                  </p>
                  <p className="font-bold text-slate-700 text-sm">
                    {orderDetail.postalCode}
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Sidebar Actions (Billing, dispatching, invoices) */}
        <div className="space-y-8">
          {/* Card 1: Procurement controls */}
          <div className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm">
            <h3 className="text-lg font-black text-slate-900 mb-6">Workflow Desk</h3>

            {/* Pending Approval Screen */}
            {orderDetail.procurementStatus === "PENDING_APPROVAL" ? (
              <div className="space-y-4">
                <div className="p-4 bg-amber-50 text-amber-800 border border-amber-100 rounded-2xl text-xs font-bold leading-relaxed">
                  ⚠️ This order is awaiting credit approval. Verify outstanding balances before releasing.
                </div>
                <Button
                  type="primary"
                  onClick={handleApprove}
                  className="bg-blue-600 hover:bg-blue-700 h-11 font-black uppercase text-xs tracking-widest rounded-xl w-full"
                >
                  Approve Order
                </Button>
                <Button
                  danger
                  onClick={() => handleUpdateStatus("CANCELLED")}
                  className="h-11 font-black uppercase text-xs tracking-widest rounded-xl w-full border border-slate-200"
                >
                  Cancel Order
                </Button>
              </div>
            ) : (
              <div className="space-y-4">
                <div>
                  <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest block mb-2">
                    Fulfillment Status
                  </label>
                  <Select
                    value={orderDetail.procurementStatus}
                    onChange={handleUpdateStatus}
                    className="w-full h-11"
                  >
                    <Select.Option value="PROCESSING">PROCESSING</Select.Option>
                    <Select.Option value="SHIPPED">SHIPPED</Select.Option>
                    <Select.Option value="PARTIALLY_SHIPPED">PARTIALLY SHIPPED</Select.Option>
                    <Select.Option value="DELIVERED">DELIVERED</Select.Option>
                    <Select.Option value="CANCELLED">CANCELLED</Select.Option>
                  </Select>
                </div>
              </div>
            )}
          </div>

          {/* Card 2: Shipping Logistics */}
          {orderDetail.procurementStatus !== "PENDING_APPROVAL" && (
            <div className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm">
              <div className="flex items-center gap-3 mb-6">
                <Truck size={20} className="text-slate-400" />
                <h3 className="text-lg font-black text-slate-900">Shipment Details</h3>
              </div>
              <div className="space-y-4">
                <div>
                  <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest block mb-2">
                    Tracking Number
                  </label>
                  <Input
                    value={trackingInput}
                    onChange={(e) => setTrackingInput(e.target.value)}
                    className="h-11 rounded-xl font-bold"
                    placeholder="Enter Tracking ID"
                  />
                </div>
                <Button
                  onClick={handleUpdateTracking}
                  className="bg-slate-100 hover:bg-slate-200 text-slate-700 border-none h-11 font-black uppercase text-xs tracking-widest rounded-xl w-full"
                >
                  Save Tracking
                </Button>
              </div>
            </div>
          )}

          {/* Card 3: Invoicing / Commercial Files */}
          <div className="bg-white rounded-3xl border border-slate-100 p-8 shadow-sm">
            <div className="flex items-center gap-3 mb-6">
              <FileText size={20} className="text-slate-400" />
              <h3 className="text-lg font-black text-slate-900">Commercial Invoices</h3>
            </div>
            <div className="space-y-5">
              {orderDetail.purchaseOrderFileUrl && (
                <a
                  href={orderDetail.purchaseOrderFileUrl}
                  target="_blank"
                  rel="noreferrer"
                  className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-2xl hover:bg-blue-50/50 hover:border-blue-100 transition-all group"
                >
                  <span className="font-bold text-slate-800 text-[13px]">
                    Buyer Purchase Order (PO)
                  </span>
                  <FileText size={16} className="text-slate-400 group-hover:text-blue-500" />
                </a>
              )}

              <div>
                <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest block mb-2">
                  Proforma Invoice URL
                </label>
                <Input
                  value={proformaInput}
                  onChange={(e) => setProformaInput(e.target.value)}
                  className="h-11 rounded-xl font-bold"
                  placeholder="Paste URL"
                />
              </div>

              <div>
                <label className="text-[11px] font-black text-slate-400 uppercase tracking-widest block mb-2">
                  Tax Invoice / Receipt URL
                </label>
                <Input
                  value={taxInvoiceInput}
                  onChange={(e) => setTaxInvoiceInput(e.target.value)}
                  className="h-11 rounded-xl font-bold"
                  placeholder="Paste URL"
                />
              </div>

              <Button
                onClick={() => handleUpdateStatus(orderDetail.procurementStatus)}
                className="bg-slate-100 hover:bg-slate-200 text-slate-700 border-none h-11 font-black uppercase text-xs tracking-widest rounded-xl w-full"
              >
                Save Invoice URL Links
              </Button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default B2bOrderDetail;
